// src/components/MobileMenuSimple.jsx
import React, { useEffect } from 'react';
import { X, Menu } from 'lucide-react';

const MobileMenuSimple = ({ isOpen, onToggle, onClose, children }) => {

  useEffect(() => {
    document.body.style.overflow = isOpen ? 'hidden' : 'unset';
    return () => { document.body.style.overflow = 'unset'; };
  }, [isOpen]);

  return (
    <>
      {/* Bouton menu */}
      <button
        className="btn btn-link p-0 border-0 d-lg-none"
        onClick={onToggle}
        aria-label="Menu"
      >
        {isOpen ? <X size={24} /> : <Menu size={24} />}
      </button>

      {/* Overlay et menu */}
      {isOpen && (
        <>
          <div
            className="position-fixed top-0 start-0 w-100 h-100 bg-dark bg-opacity-50"
            style={{ zIndex: 1040 }}
            onClick={onClose}
          />
          <div
            className="position-fixed top-0 end-0 h-100 bg-white shadow"
            style={{
              width: '280px',
              zIndex: 1050,
              animation: 'slideIn 0.3s ease',
              overflowY: 'auto'
            }}
          >
            <div className="p-4">
              <div className="d-flex justify-content-between align-items-center mb-4">
                <h5 className="mb-0">Menu</h5>
                <button className="btn btn-link p-0" onClick={onClose}>
                  <X size={24} />
                </button>
              </div>
              {children}
            </div>
          </div>
        </>
      )}

      <style>{`
        @keyframes slideIn {
          from { transform: translateX(100%); }
          to { transform: translateX(0); }
        }
      `}</style>
    </>
  );
};

export default MobileMenuSimple;
